// Import all exports from the mock API service
export {
  authAPI,
  superAdminAPI,
  farmersAPI,
  employeesAPI,
  adminAPI,
  kycAPI,
  dashboardAPI,
  registrationsAPI,
  employeeAPI,
  apiService
} from './mockApiService';

// Re-export the default export from mock API service
export { default } from './mockApiService';
